    "cases.mark_up_and_compare_a_drawing_revision.step.open.out.status": "Bekræftet revision og dato",
    "cases.mark_up_and_compare_a_drawing_revision.step.open.title": "Åbn den aktuelle tegningsrevision",
    "cases.mark_up_and_compare_a_drawing_revision.step.open.what": "Find arket i projektfilerne, og åbn dets nyeste revision. Tjek revisionsbogstav og dato, så du markerer den aktive tegning og ikke en forældet.",
    "cases.mark_up_and_compare_a_drawing_revision.step.open.why": "En markering på sidste måneds ark er spildt i samme øjeblik den lander, og værre endnu kan den få projekteringsteamet til at rette en detalje, der allerede er ændret. Start fra den kontrollerede, aktuelle revision hver gang.",
    "cases.mark_up_and_compare_a_drawing_revision.step.redline.in.issues": "Konflikter og spørgsmål fra pladsen",
    "cases.mark_up_and_compare_a_drawing_revision.step.redline.in.sheet": "Aktivt tegningsark",
    "cases.mark_up_and_compare_a_drawing_revision.step.redline.out.comments": "Projekteringsspørgsmål",
    "cases.mark_up_and_compare_a_drawing_revision.step.redline.out.markup": "Ark med røde markeringer",
    "cases.mark_up_and_compare_a_drawing_revision.step.redline.title": "Marker tegningen med røde noter",
    "cases.mark_up_and_compare_a_drawing_revision.step.redline.what": "Marker arket med skyer, mål og kommentarer, hvor tegningen kolliderer med pladsen eller kræver et svar fra projekteringen, og adressér hver note til projekteringsteamet.",
    "cases.mark_up_and_compare_a_drawing_revision.step.redline.why": "En tydelig rød markering på selve tegningen fortæller projekterende præcis hvor og hvad, så spørgsmålet kommer tilbage som en ordentlig revision i stedet for en vag mailtråd, der trækker ud i ugevis.",
    "cases.mark_up_and_compare_a_drawing_revision.title": "Marker og sammenlign en tegningsrevision",
    "cases.material_submittal_and_approval.desc": "Læg det produkt, du planlægger at købe, frem for projekterende med dataene bag det, få det tjekket op mod specifikationen, og frigiv det først til bestilling, når det er godkendt.",
    "cases.material_submittal_and_approval.step.release.in.approval": "Godkendelsesbeslutning",
    "cases.material_submittal_and_approval.step.release.in.product": "Godkendt produkt",
    "cases.material_submittal_and_approval.step.release.out.linked": "Ordre knyttet til materialegodkendelse",
    "cases.material_submittal_and_approval.step.release.out.order": "Indkøbsordre",
    "cases.material_submittal_and_approval.step.release.title": "Frigiv til bestilling",
    "cases.material_submittal_and_approval.step.release.what": "Når materialegodkendelsen er godkendt, opret indkøbsordren på præcis det produkt, der blev godkendt, og angiv godkendelsens reference på ordren, så pladsen og leverandøren leverer den godkendte vare og intet andet.",
    "cases.material_submittal_and_approval.step.release.why": "Godkendelsen har kun værdi, hvis det, der dukker op på pladsen, er det, der blev godkendt. At binde ordren tilbage til godkendelsens reference er det, der forhindrer en leverandør i stilfærdigt at bytte til et billigere alternativ.",
    "cases.material_submittal_and_approval.step.review.in.spec": "Krav i specifikationen",
    "cases.material_submittal_and_approval.step.review.in.submittal": "Videresendt materialegodkendelse",
    "cases.material_submittal_and_approval.step.review.out.decision": "Godkendelsesbeslutning",
    "cases.material_submittal_and_approval.step.review.out.deviations": "Registrerede afvigelser",
    "cases.material_submittal_and_approval.step.review.title": "Tjek det op mod specifikationen",
    "cases.material_submittal_and_approval.step.review.what": "Stil det indsendte produkt op mod den specificerede ydeevne, finish og standarder, punkt for punkt, og registrer resultatet: godkendt, godkendt med bemærkninger eller afvist med begrundelse. Registrer enhver afvigelse, projekterende accepterer, så den ikke tages op igen senere.",
    "cases.material_submittal_and_approval.step.review.why": "En tjekket materialegodkendelse er det øjeblik, hvor en udskiftning fanges, før den bygges ind, ikke efter. Den registrerede beslutning er det, der beskytter dig, når bygherren spørger, hvorfor det monterede produkt afviger fra tegningerne.",
    "cases.material_submittal_and_approval.step.submit.in.clause": "Specifikationspunkt",
    "cases.material_submittal_and_approval.step.submit.in.data": "Datablade og certifikater",
    "cases.material_submittal_and_approval.step.submit.in.product": "Foreslået produkt",
    "cases.material_submittal_and_approval.step.submit.out.deadline": "Behøves-senest-dato",
    "cases.material_submittal_and_approval.step.submit.out.submittal": "Videresendt materialegodkendelse",
    "cases.material_submittal_and_approval.step.submit.title": "Opret materialegodkendelsen",
    "cases.material_submittal_and_approval.step.submit.what": "Opret materialegodkendelsen for det produkt, du vil bruge, vedhæft datablad, prøver og certifikater, og angiv det specifikationspunkt, det tilbydes op mod. Videresend den til den projekterende, der skal godkende den, og sæt en behøves-senest-dato bundet til, hvornår du skal bestille for at ramme tidsplanen.",
    "cases.material_submittal_and_approval.step.submit.why": "At bestille et materiale, før det er godkendt, er sådan du ender med en container fuld af det forkerte produkt og en strid om, hvem der betaler. En dateret materialegodkendelse sætter også uret i gang for projekterende, så en langsom godkendelse, der forsinker din bestilling, er dokumenteret.",
    "cases.material_submittal_and_approval.title": "Få en materialegodkendelse godkendt",
    "cases.milestone_progress_before_drawdown.desc": "Bekræft at tidsplanen reelt har nået sin milepæl, kryds-tjek den op mod earned value, og godkend først derefter den opgørelse, der frigiver midler mod den.",
    "cases.milestone_progress_before_drawdown.step.approve.in.amount": "Opgørelsesbeløb",
    "cases.milestone_progress_before_drawdown.step.approve.in.ev": "Earned value-aflæsning",
    "cases.milestone_progress_before_drawdown.step.approve.in.status": "Milepælsstatus",
    "cases.milestone_progress_before_drawdown.step.approve.out.approved": "Godkendt opgørelse",
    "cases.milestone_progress_before_drawdown.step.approve.out.drawdown": "Frigivet udbetaling",
