    "cases.milestone_progress_before_drawdown.step.earned.in.spend": "Omkostning til dato",
    "cases.milestone_progress_before_drawdown.step.earned.out.consistency": "Konsistenstjek af krav",
    "cases.milestone_progress_before_drawdown.step.earned.out.ev": "Earned value-aflæsning",
    "cases.milestone_progress_before_drawdown.step.earned.title": "Aflæs earned value til dato",
    "cases.milestone_progress_before_drawdown.step.earned.what": "Tjek den indtjente værdi til dato op mod, hvad der er brugt, og hvad der var planlagt, så milepælskravet stemmer med det bredere omkostningsbillede.",
    "cases.milestone_progress_before_drawdown.step.earned.why": "En milepæl kan se nået ud på tidsplanen, mens omkostnings- og earned value-billedet fortæller en anden historie. At læse begge samlet er det, der fanger en uoverensstemmelse, før den bliver betalt.",
    "cases.milestone_progress_before_drawdown.step.milestones.in.claim": "Krævet milepæl",
    "cases.milestone_progress_before_drawdown.step.milestones.in.schedule": "Projekttidsplan",
    "cases.milestone_progress_before_drawdown.step.milestones.out.progress": "Verificeret fremdrift",
    "cases.milestone_progress_before_drawdown.step.milestones.out.status": "Bekræftet milepælsstatus",
    "cases.milestone_progress_before_drawdown.step.milestones.title": "Tjek milepælen op mod tidsplanen",
    "cases.milestone_progress_before_drawdown.step.milestones.what": "Åbn tidsplanen, og bekræft at den milepæl, opgørelsen kræves mod, faktisk er nået, ikke bare er tæt på.",
    "cases.milestone_progress_before_drawdown.step.milestones.why": "En milepæl, der kræves en uge for tidligt og betales mod, er penge frigivet for arbejde, der endnu ikke er udført, og det er besværligt at kræve tilbage.",
    "cases.milestone_progress_before_drawdown.title": "Tjek milepælsfremdrift, før en opgørelse godkendes",
    "cases.model_quality_audit_before_issue.desc": "Kør de tjek, der fanger en dårlig model, før en bygherre eller et pladssjak åbner den: koordinatgrundlag, aktive kollisioner og fuldstændig klassifikation.",
    "cases.model_quality_audit_before_issue.step.base.in.model": "Fagmodel",
