    "cases.quantities_from_bim.step.validate.what": "Kør valideringsreglerne for at bekræfte, at de kortlagte mængder er fuldstændige og konsistente, og at der er en klassifikation til stede, hvor regelsættet kræver en.",
    "cases.quantities_from_bim.step.validate.why": "En model kan se fuldstændig ud og stadig mangle netop den egenskab, du skal bruge til prissætning. Valideringen fanger det ukortlagte element og den tomme klassifikation, før tilbudslisten når bygherren.",
    "cases.quantities_from_bim.title": "Hent mængder fra en BIM-model",
    "cases.record_a_verbal_instruction_for_the_record.desc": "En mundtlig instruks giver dig intet, du kan bevise. Log opkaldet, mens det er friskt, bekræft det skriftligt, og hvis det ændrede omfanget, så start ændringssagen, før du bygger det.",
    "cases.record_a_verbal_instruction_for_the_record.step.confirm.in.log": "Dateret opkaldslog",
    "cases.record_a_verbal_instruction_for_the_record.step.confirm.in.understanding": "Forstået instruks",
    "cases.record_a_verbal_instruction_for_the_record.step.confirm.out.filed": "Arkiveret korrespondance",
    "cases.record_a_verbal_instruction_for_the_record.step.confirm.out.note": "Bekræftelsesnotat",
    "cases.record_a_verbal_instruction_for_the_record.step.confirm.title": "Bekræft det skriftligt",
    "cases.record_a_verbal_instruction_for_the_record.step.confirm.what": "Send et kort notat med bekræftelse af mundtlig instruks tilbage til den, der gav den, med hvad du forstod, og at du handler på den, medmindre andet meddeles. Arkivér det på projektet.",
    "cases.record_a_verbal_instruction_for_the_record.step.confirm.why": "En mundtlig instruks binder først, når den er skrevet ned og står uimodsagt. Bekræftelsesnotatet gør en samtale på gangen til en instruks, du kan stole på og, senere, blive betalt for.",
    "cases.record_a_verbal_instruction_for_the_record.step.log.in.call": "Mundtlig instruks",
    "cases.record_a_verbal_instruction_for_the_record.step.log.in.caller": "Opkalder og tidspunkt",
    "cases.record_a_verbal_instruction_for_the_record.step.log.out.entry": "Dateret opkaldslog",
    "cases.record_a_verbal_instruction_for_the_record.step.log.out.record": "Instruks på skrift",
    "cases.record_a_verbal_instruction_for_the_record.step.log.title": "Log opkaldet",
    "cases.record_a_verbal_instruction_for_the_record.step.log.what": "Lige efter opkaldet, log det, hvem der ringede, hvornår, og præcis hvad der blev sagt eller instrueret, med deres ord frem for din omskrivning. Gør det, mens du stadig husker detaljen.",
    "cases.record_a_verbal_instruction_for_the_record.step.log.why": "Fjorten dage senere er ingen enige om, hvad der blev sagt i telefonen. En dateret log skrevet i samme time er forskellen på en kendsgerning og dit ord mod deres.",
    "cases.record_a_verbal_instruction_for_the_record.step.record.in.note": "Bekræftelsesnotat",
    "cases.record_a_verbal_instruction_for_the_record.step.record.in.scope": "Ændring af omfang",
    "cases.record_a_verbal_instruction_for_the_record.step.record.out.entitlement": "Tilgodehavende logget",
    "cases.record_a_verbal_instruction_for_the_record.step.record.out.order": "Ændringsordre",
    "cases.record_a_verbal_instruction_for_the_record.step.record.title": "Start ændringssagen, hvis omfanget ændrede sig",
    "cases.record_a_verbal_instruction_for_the_record.step.record.what": "Hvis instruksen føjede til eller ændrede omfanget, opret ændringsordren nu, før arbejdet udføres, så det ekstra registreres mod en aftalt begrundelse, og uret starter på dit tilgodehavende.",
    "cases.record_a_verbal_instruction_for_the_record.step.record.why": "Arbejde, der udføres først og papirføres bagefter, er det arbejde, der aldrig bliver betalt. At starte ændringssagen, før du handler, er det, der forhindrer en mundtlig instruks i at blive til gratis arbejde.",
    "cases.record_a_verbal_instruction_for_the_record.title": "Registrér en mundtlig instruks til sagen",
    "cases.report_and_action_a_near_miss.desc": "Log nærved-hændelsen, mens detaljen er frisk, find årsagen og fastsæt den korrigerende handling, og tjek så på rundgangen, at foranstaltningen faktisk er på plads.",
    "cases.report_and_action_a_near_miss.step.action.in.controls": "Svigtet foranstaltning",
    "cases.report_and_action_a_near_miss.step.action.in.report": "Logget nærved-hændelse",
    "cases.report_and_action_a_near_miss.step.action.out.action": "Korrigerende handling",
    "cases.report_and_action_a_near_miss.step.action.out.cause": "Grundårsag",
    "cases.report_and_action_a_near_miss.step.action.title": "Find årsagen og handl",
    "cases.report_and_action_a_near_miss.step.action.what": "Se forbi den umiddelbare udløser til, hvorfor foranstaltningen svigtede, fastsæt derefter den korrigerende handling med en udpeget ejer og en frist, og orientér det bredere sjak, hvis den samme risiko findes andre steder på pladsen.",
    "cases.report_and_action_a_near_miss.step.action.why": "At give den, der gled, skylden løser intet; den manglende afskærmning eller den dårlige adgang fanger også den næste arbejder. At rette årsagen er det, der faktisk fjerner faren i stedet for at flytte den videre.",
    "cases.report_and_action_a_near_miss.step.report.in.event": "Observation af nærved-hændelse",
    "cases.report_and_action_a_near_miss.step.report.in.scene": "Foto af stedet",
    "cases.report_and_action_a_near_miss.step.report.out.report": "Logget nærved-hændelse",
    "cases.report_and_action_a_near_miss.step.report.out.severity": "Vurdering af potentiel skade",
    "cases.report_and_action_a_near_miss.step.report.title": "Log nærved-hændelsen",
    "cases.report_and_action_a_near_miss.step.report.what": "Registrér hvad der skete, hvor og hvornår, hvem der var involveret, og hvilken skade det kunne have forvoldt, med et foto af stedet. Fang det på samme vagt, før hukommelsen falmer, og stedet ryddes.",
    "cases.report_and_action_a_near_miss.step.report.why": "En nærved-hændelse er en gratis advarsel: den skade, den peger på, er ikke sket endnu. At logge den, mens den er frisk, er det, der lader dig rette årsagen, før næste gang gør den til en rigtig ulykke.",
    "cases.report_and_action_a_near_miss.step.verify.in.action": "Korrigerende handling",
    "cases.report_and_action_a_near_miss.step.verify.in.walk": "Inspektionsrundgang",
    "cases.report_and_action_a_near_miss.step.verify.out.closed": "Nærved-hændelse lukket",
    "cases.report_and_action_a_near_miss.step.verify.out.verified": "Foranstaltning verificeret",
    "cases.report_and_action_a_near_miss.step.verify.title": "Verificér rettelsen på rundgangen",
    "cases.report_and_action_a_near_miss.step.verify.what": "Gå tilbage til stedet på næste inspektionsrundgang, bekræft at den korrigerende handling reelt er udført og holder, og luk nærved-hændelsen med dokumentationen vedhæftet.",
    "cases.report_and_action_a_near_miss.step.verify.why": "En handling markeret som udført på kontoret er ikke det samme som en afskærmning, der står ude på pladsen. At tjekke den på rundgangen er det, der gør en god hensigt til beskyttelse, en arbejder kan læne sig op ad.",
    "cases.report_and_action_a_near_miss.title": "Rapportér og følg op på en nærved-hændelse",
    "cases.review_and_mitigate_project_risks.desc": "Gennemgå risikoregistret med jævne mellemrum, vurdér sandsynlighed og konsekvens ærligt, og udpeg en ansvarlig for afværgning, før en risiko bliver til et reelt problem.",
    "cases.review_and_mitigate_project_risks.step.mitigate.in.risks": "Aktive risici",
    "cases.review_and_mitigate_project_risks.step.mitigate.in.team": "Tilgængelige ansvarlige",
    "cases.review_and_mitigate_project_risks.step.mitigate.out.actions": "Afværgeforanstaltninger",
