    "cases.review_and_mitigate_project_risks.step.review.what": "Gennemgå hver åben risiko i registret, genvurdér dens sandsynlighed og konsekvens ud fra det, du nu ved, og udfas alt, der reelt er overstået.",
    "cases.review_and_mitigate_project_risks.step.review.why": "Et risikoregister, som ingen vender tilbage til, hober bare forældede poster op og skjuler de to-tre, der faktisk betyder noget denne måned.",
    "cases.review_and_mitigate_project_risks.title": "Gennemgå og afværg risikoregistret",
    "cases.run_a_handover_acceptance_inspection.desc": "Gå det færdige arbejde igennem med bygherren, registrér hvad der består og hvad der ikke gør op mod acceptkriterierne, kør mangellisten ned til nul, og udsted en ren godkendelse.",
    "cases.run_a_handover_acceptance_inspection.step.accept.in.record": "Inspektionsregistrering",
    "cases.run_a_handover_acceptance_inspection.step.accept.in.zero": "Mangelliste på nul",
    "cases.run_a_handover_acceptance_inspection.step.accept.out.defects": "Mangelperiode startet",
