    "cases.run_a_progress_meeting_and_drive_the_actions.step.issue-minutes.title": "Udsend referat og handlinger",
    "cases.run_a_progress_meeting_and_drive_the_actions.step.issue-minutes.what": "Generér referatet og listen over åbne handlinger, og send dem til alle, der deltog.",
    "cases.run_a_progress_meeting_and_drive_the_actions.step.issue-minutes.why": "Et referat binder først folk, når det er udsendt. At udsende handlingerne lukker sløjfen og starter uret på hver frist.",
    "cases.run_a_progress_meeting_and_drive_the_actions.step.rfi.in.minutes": "Mødereferat",
