    "cases.set_up_a_new_project.step.schedule.out.fronts": "Daterede arbejdsfronter",
    "cases.set_up_a_new_project.step.schedule.out.programme": "Overordnet tidsplan",
    "cases.set_up_a_new_project.step.schedule.title": "Læg den første tidsplan",
    "cases.set_up_a_new_project.step.schedule.what": "Åbn tidsplanen og skitsér de store faser med grove varigheder og den rækkefølge, fagene følger, fra forberedende arbejder frem til aflevering. Sæt start- og måldatoen for færdiggørelse.",
    "cases.set_up_a_new_project.step.schedule.why": "Selv en grov tidsplan gør et prissat omfang til daterede arbejdsfronter og viser med det samme, om slutdatoen er realistisk. Den giver teamet et fælles billede af projektet, længe før detaljerne er fyldt ind.",
    "cases.set_up_a_new_project.title": "Opret et nyt projekt",
    "cases.set_up_bim_requirements_and_coordination.desc": "Skriv ned, hvilke oplysninger bygherren faktisk har brug for fra modellerne, fastlæg den sammenstillings- og koordineringsrytme, der skal levere dem, og kontroller så, at de modeller, der kommer retur, bærer de egenskaber, du bad om.",
    "cases.set_up_bim_requirements_and_coordination.step.confirm.in.matrix": "Kravmatrix",
    "cases.set_up_bim_requirements_and_coordination.step.confirm.in.models": "Leverede modeller",
    "cases.set_up_bim_requirements_and_coordination.step.confirm.out.check": "Overensstemmelseskontrol",
    "cases.set_up_bim_requirements_and_coordination.step.confirm.out.gaps": "Manglende egenskaber markeret",
    "cases.set_up_bim_requirements_and_coordination.step.confirm.title": "Bekræft, at modellerne overholder kravene",
    "cases.set_up_bim_requirements_and_coordination.step.confirm.what": "Åbn de leverede modeller i vieweren, og kontroller, at bygningsdelene faktisk bærer de egenskaber, klassifikationer og det detaljeringsniveau, kravene foreskrev.",
    "cases.set_up_bim_requirements_and_coordination.step.confirm.why": "Kravet betyder kun noget, hvis du kontrollerer op mod det. At fange en model med manglende egenskaber ved leveringen er en genudsendelse, at fange det ved afleveringen er en kamp for at genskabe data, ingen har gemt.",
    "cases.set_up_bim_requirements_and_coordination.step.coordinate.in.matrix": "Kravmatrix",
    "cases.set_up_bim_requirements_and_coordination.step.coordinate.in.models": "Fagmodeller",
    "cases.set_up_bim_requirements_and_coordination.step.coordinate.out.cadence": "Koordineringsplan",
    "cases.set_up_bim_requirements_and_coordination.step.coordinate.out.federation": "Modelsammenstilling",
    "cases.set_up_bim_requirements_and_coordination.step.coordinate.title": "Fastlæg koordineringsrytmen",
    "cases.set_up_bim_requirements_and_coordination.step.coordinate.what": "Opsæt sammenstillingen og den faste koordineringscyklus op mod de krav: hvem leverer hvad, hvornår modellerne samles, og hvor ofte teamet mødes for at rydde konflikter af vejen.",
    "cases.set_up_bim_requirements_and_coordination.step.coordinate.why": "Koordinering, der sker, når nogen husker det, sker for sent. En fast rytme knyttet til kravene holder fagene i takt i stedet for at kollidere på pladsen.",
    "cases.set_up_bim_requirements_and_coordination.step.requirements.in.brief": "Bygherreoplæg",
    "cases.set_up_bim_requirements_and_coordination.step.requirements.in.standards": "Gældende standarder",
