    "cases.set_up_bim_requirements_and_coordination.step.requirements.out.properties": "Egenskabsskema",
    "cases.set_up_bim_requirements_and_coordination.step.requirements.title": "Fastlæg informationskravene",
    "cases.set_up_bim_requirements_and_coordination.step.requirements.what": "Registrer bygherrens informationskrav som en matrix: hvilke modeller, på hvilke stadier, med hvilke egenskaber og efter hvis standard.",
    "cases.set_up_bim_requirements_and_coordination.step.requirements.why": "En model, der afleveres uden de egenskaber, nogen har brug for, er et pænt billede, ikke et aktiv. At skrive kravet ned først er det, der gør det til noget, du kan holde en projekterende fast på.",
    "cases.set_up_bim_requirements_and_coordination.title": "Opsæt BIM-krav og koordinering",
    "cases.set_up_the_asset_register_for_fm.desc": "Byg det aktivregister, den driftsansvarlige vil drive bygningen ud fra: registrer de installerede aktiver med deres placering, type og nøgledata, vedhæft manualerne og garantierne, og overdrag det, så vedligeholdet kan starte fra dag ét.",
    "cases.set_up_the_asset_register_for_fm.step.attach.in.manuals": "Driftsmanualer",
    "cases.set_up_the_asset_register_for_fm.step.attach.in.register": "Placeret aktivregister",
    "cases.set_up_the_asset_register_for_fm.step.attach.in.warranties": "Garantier og reservedele",
    "cases.set_up_the_asset_register_for_fm.step.attach.out.linked": "Dokumenter tilknyttet",
    "cases.set_up_the_asset_register_for_fm.step.attach.out.register": "Komplet aktivregister",
    "cases.set_up_the_asset_register_for_fm.step.attach.title": "Vedhæft manualer og garantier",
    "cases.set_up_the_asset_register_for_fm.step.attach.what": "Knyt hvert aktiv til dets driftsmanual, reservedelsliste og garanti, så det at åbne aktivet giver vedligeholderen alt, hvad han har brug for, uden en separat søgning.",
    "cases.set_up_the_asset_register_for_fm.step.attach.why": "Et register med dokumenterne vedhæftet gør et navn på en liste til et brugbart kartotek. Uden manualen og garantien inden for rækkevidde er vedligeholderen tilbage til at gætte, og garantien er let at overse.",
    "cases.set_up_the_asset_register_for_fm.step.capture.in.asbuilt": "As-built-dokumentation",
    "cases.set_up_the_asset_register_for_fm.step.capture.in.equipment": "Installeret udstyr",
    "cases.set_up_the_asset_register_for_fm.step.capture.out.list": "Liste over mærkede aktiver",
    "cases.set_up_the_asset_register_for_fm.step.capture.out.tags": "Aktivmærker",
    "cases.set_up_the_asset_register_for_fm.step.capture.title": "Registrer de installerede aktiver",
    "cases.set_up_the_asset_register_for_fm.step.capture.what": "Oplist hvert vedligeholdelseskrævende aktiv, der faktisk blev installeret, dets type, fabrikat og model, og giv hvert et mærke, så det kan findes og henvises til uden tvivl.",
    "cases.set_up_the_asset_register_for_fm.step.capture.why": "Registret er kun nyttigt, hvis det svarer til bygningen. Et aktiv, der blev skiftet ud under byggeriet, men aldrig opdateret på listen, efterlader den driftsansvarlige med at vedligeholde en maskine, der aldrig blev monteret.",
    "cases.set_up_the_asset_register_for_fm.step.handover.in.register": "Komplet aktivregister",
    "cases.set_up_the_asset_register_for_fm.step.handover.in.team": "Vedligeholdelsesteam",
    "cases.set_up_the_asset_register_for_fm.step.handover.out.issued": "Udleveret register",
    "cases.set_up_the_asset_register_for_fm.step.handover.out.ppm": "Klar til vedligehold fra dag ét",
    "cases.set_up_the_asset_register_for_fm.step.handover.out.summary": "Dækningsoversigt",
    "cases.set_up_the_asset_register_for_fm.step.handover.title": "Overdrag, så vedligeholdet kan starte",
    "cases.set_up_the_asset_register_for_fm.step.handover.what": "Udlever det færdige register til vedligeholdelsesteamet som det kartotek, de vil arbejde ud fra, og lav en oversigt over, hvad det dækker, så planlagt vedligehold kan sættes op fra dag ét med det samme.",
    "cases.set_up_the_asset_register_for_fm.step.handover.why": "Pointen med registret er en bygning i drift, ikke et arkiveret dokument. At overdrage det klar til brug er det, der lader den driftsansvarlige starte planlagt vedligehold fra dag ét i stedet for selv at genopbygge listen.",
    "cases.set_up_the_asset_register_for_fm.step.locate.in.assets": "Liste over mærkede aktiver",
    "cases.set_up_the_asset_register_for_fm.step.locate.in.layout": "Etage- og rumplan",
    "cases.set_up_the_asset_register_for_fm.step.locate.in.specs": "Udstyrsspecifikationer",
    "cases.set_up_the_asset_register_for_fm.step.locate.out.data": "Nøgledata for aktivet",
    "cases.set_up_the_asset_register_for_fm.step.locate.out.located": "Placerede aktiver",
    "cases.set_up_the_asset_register_for_fm.step.locate.title": "Registrer placering og nøgledata",
    "cases.set_up_the_asset_register_for_fm.step.locate.what": "For hvert aktiv registreres, hvor det sidder, etage, rum og det system, det betjener, sammen med de nøgledata en vedligeholder har brug for, såsom mærkeeffekt, kapacitet og serviceintervaller.",
    "cases.set_up_the_asset_register_for_fm.step.locate.why": "Når en enhed svigter, er det første spørgsmål altid, hvor den er, og hvad den betjener. Et register, der besvarer det på én linje, sparer vedligeholdelsesteamet timers søgen gennem teknikrum og lofter.",
    "cases.set_up_the_asset_register_for_fm.title": "Opsæt aktivregistret til FM",
    "cases.set_up_the_common_data_environment.desc": "Sæt det fælles datamiljø op, indlæs informationscontainerne med den rigtige status, og ret koordineringen mod det delte område.",
